@Override
	public int[] batchUpdate(String sql, List<Object[]> batchArgs, int[] argTypes) throws DataAccessException {
		if (batchArgs.isEmpty()) {
			return new int[0];
		}

		return batchUpdate(
				sql,
				new BatchPreparedStatementSetter() {
					@Override
					public void setValues(PreparedStatement ps, int i) throws SQLException {
						Object[] values = batchArgs.get(i);
						int colIndex = 0;
						for (Object value : values) {
							colIndex++;
							if (value instanceof SqlParameterValue paramValue) {
								StatementCreatorUtils.setParameterValue(ps, colIndex, paramValue, paramValue.getValue());
							}
							else {
								int colType;
								if (argTypes.length < colIndex) {
									colType = SqlTypeValue.TYPE_UNKNOWN;
								}
								else {
									colType = argTypes[colIndex - 1];
								}
								StatementCreatorUtils.setParameterValue(ps, colIndex, colType, value);
							}
						}
					}
					@Override
					public int getBatchSize() {
						return batchArgs.size();
					}
				});
	}

protected Mono<Void> doCommit(@Nullable Supplier<? extends Mono<Void>> writeAction) {
	Flux<Void> allActions = Flux.empty();
	if (this.state.compareAndSet(State.NEW, State.COMMITTING)) {
		if (!this.commitActions.isEmpty()) {
			allActions = Flux.concat(Flux.fromIterable(this.commitActions).map(Supplier::get))
					.doOnError(ex -> {
						if (this.state.compareAndSet(State.COMMITTING, State.COMMIT_ACTION_FAILED)) {
							getHeaders().clearContentHeaders();
						}
					});
		}
	}
	else if (this.state.compareAndSet(State.COMMIT_ACTION_FAILED, State.COMMITTING)) {
		// Skip commit actions
	}
	else {
		return Mono.empty();
	}

	allActions = allActions.concatWith(Mono.fromRunnable(() -> {
		applyStatusCode();
		applyHeaders();
		applyCookies();
		this.state.set(State.COMMITTED);
	}));

	if (writeAction != null) {
		allActions = allActions.concatWith(writeAction.get());
	}

	return allActions.then();
}

@Override
	public @Nullable Authentication convert(HttpServletRequest request) {
		X509Certificate[] clientCertificateChain = (X509Certificate[]) request
			.getAttribute("jakarta.servlet.request.X509Certificate");
		if (clientCertificateChain == null || clientCertificateChain.length == 0) {
			return null;
		}

		MultiValueMap<String, String> parameters = OAuth2EndpointUtils.getFormParameters(request);

		// client_id (REQUIRED)
		String clientId = parameters.getFirst(OAuth2ParameterNames.CLIENT_ID);
		if (!StringUtils.hasText(clientId)) {
			return null;
		}

		List<String> clientIdParams = parameters.get(OAuth2ParameterNames.CLIENT_ID);
		if (clientIdParams == null || clientIdParams.size() != 1) {
			throw new OAuth2AuthenticationException(OAuth2ErrorCodes.INVALID_REQUEST);
		}

		Map<String, Object> additionalParameters = OAuth2EndpointUtils
			.getParametersIfMatchesAuthorizationCodeGrantRequest(request, OAuth2ParameterNames.CLIENT_ID);

		ClientAuthenticationMethod clientAuthenticationMethod = (clientCertificateChain.length == 1)
				? ClientAuthenticationMethod.SELF_SIGNED_TLS_CLIENT_AUTH : ClientAuthenticationMethod.TLS_CLIENT_AUTH;

		return new OAuth2ClientAuthenticationToken(clientId, clientAuthenticationMethod, clientCertificateChain,
				additionalParameters);
	}

static OAuth2AuthorizationResponse convert(MultiValueMap<String, String> request, String redirectUri) {
	String code = request.getFirst(OAuth2ParameterNames.CODE);
	String errorCode = request.getFirst(OAuth2ParameterNames.ERROR);
	String state = request.getFirst(OAuth2ParameterNames.STATE);
	if (StringUtils.hasText(code)) {
		OAuth2AuthorizationResponse.Builder builder = OAuth2AuthorizationResponse.success(code)
			.redirectUri(redirectUri);
		if (state != null) {
			builder.state(state);
		}
		return builder.build();
	}
	if (!StringUtils.hasText(errorCode)) {
		errorCode = "unknown_error";
	}
	String errorDescription = request.getFirst(OAuth2ParameterNames.ERROR_DESCRIPTION);
	String errorUri = request.getFirst(OAuth2ParameterNames.ERROR_URI);
	OAuth2AuthorizationResponse.Builder builder = OAuth2AuthorizationResponse.error(errorCode)
		.redirectUri(redirectUri);
	if (errorDescription != null) {
		builder.errorDescription(errorDescription);
	}
	if (errorUri != null) {
		builder.errorUri(errorUri);
	}
	if (state != null) {
		builder.state(state);
	}
	return builder.build();
}

@Override
	public void commence(HttpServletRequest request, HttpServletResponse response,
			AuthenticationException authException) {
		HttpStatus status = HttpStatus.UNAUTHORIZED;
		Map<String, String> parameters = new LinkedHashMap<>();
		if (this.realmName != null) {
			parameters.put("realm", this.realmName);
		}
		if (authException instanceof OAuth2AuthenticationException oAuth2AuthenticationException) {
			OAuth2Error error = oAuth2AuthenticationException.getError();
			parameters.put("error", error.getErrorCode());
			if (StringUtils.hasText(error.getDescription())) {
				parameters.put("error_description", error.getDescription());
			}
			if (StringUtils.hasText(error.getUri())) {
				parameters.put("error_uri", error.getUri());
			}
			if (error instanceof BearerTokenError bearerTokenError) {
				if (StringUtils.hasText(bearerTokenError.getScope())) {
					parameters.put("scope", bearerTokenError.getScope());
				}
				status = bearerTokenError.getHttpStatus();
			}
		}
		parameters.put("resource_metadata", this.resourceMetadataParameterResolver.apply(request));
		String wwwAuthenticate = computeWWWAuthenticateHeaderValue(parameters);
		response.addHeader(HttpHeaders.WWW_AUTHENTICATE, wwwAuthenticate);
		response.setStatus(status.value());
	}

@Override
	public Mono<MatchResult> matches(ServerWebExchange exchange) {
		ServerHttpRequest request = exchange.getRequest();
		PathContainer path = request.getPath().pathWithinApplication();
		if (this.method != null && !this.method.equals(request.getMethod())) {
			return MatchResult.notMatch().doOnNext((result) -> {
				if (logger.isDebugEnabled()) {
					logger.debug("Request '" + request.getMethod() + " " + path + "' doesn't match '" + this.method
							+ " " + this.pattern.getPatternString() + "'");
				}
			});
		}

		PathPattern.PathMatchInfo pathMatchInfo = this.pattern.matchAndExtract(path);
		if (pathMatchInfo == null) {
			return MatchResult.notMatch().doOnNext((result) -> {
				if (logger.isDebugEnabled()) {
					logger.debug("Request '" + request.getMethod() + " " + path + "' doesn't match '" + this.method
							+ " " + this.pattern.getPatternString() + "'");
				}
			});
		}
		Map<String, String> pathVariables = pathMatchInfo.getUriVariables();
		Map<String, Object> variables = new HashMap<>(pathVariables);
		if (logger.isDebugEnabled()) {
			logger
				.debug("Checking match of request : '" + path + "'; against '" + this.pattern.getPatternString() + "'");
		}
		return MatchResult.match(variables);
	}

try {
	taskExecutor.execute(new Runnable() {

		@Override
		public void run() {
			try {
				if (logger.isInfoEnabled()) {
					logger.info("Job: [" + job + "] launched with the following parameters: [" + jobParameters
							+ "]");
				}
				job.execute(jobExecution);
				if (logger.isInfoEnabled()) {
					Duration jobExecutionDuration = BatchMetrics.calculateDuration(jobExecution.getStartTime(),
							jobExecution.getEndTime());
					logger.info("Job: [" + job + "] completed with the following parameters: [" + jobParameters
							+ "] and the following status: [" + jobExecution.getStatus() + "]"
							+ (jobExecutionDuration == null ? ""
									: " in " + BatchMetrics.formatDuration(jobExecutionDuration)));
				}
			}
			catch (Throwable t) {
				if (logger.isInfoEnabled()) {
					logger.info("Job: [" + job
							+ "] failed unexpectedly and fatally with the following parameters: ["
							+ jobParameters + "]", t);
				}
				rethrow(t);
			}
		}

		private void rethrow(Throwable t) {
			if (t instanceof RuntimeException runtimeException) {
				throw runtimeException;
			}
			else if (t instanceof Error error) {
				throw error;
			}
			throw new IllegalStateException(t);
		}
	});
}

@Override
	public ExitStatus run(String... args) throws Exception {
		if (args.length == 0) {
			throw new NoHelpCommandArgumentsException();
		}
		String commandName = args[0];
		for (Command command : this.commandRunner) {
			if (command.getName().equals(commandName)) {
				Log.info(this.commandRunner.getName() + command.getName() + " - " + command.getDescription());
				Log.info("");
				if (command.getUsageHelp() != null) {
					Log.info("usage: " + this.commandRunner.getName() + command.getName() + " "
							+ command.getUsageHelp());
					Log.info("");
				}
				if (command.getHelp() != null) {
					Log.info(command.getHelp());
				}
				Collection<HelpExample> examples = command.getExamples();
				if (examples != null) {
					Log.info((examples.size() != 1) ? "examples:" : "example:");
					Log.info("");
					for (HelpExample example : examples) {
						Log.info("    " + example.getDescription() + ":");
						Log.info("        $ " + example.getExample());
						Log.info("");
					}
					Log.info("");
				}
				return ExitStatus.OK;
			}
		}
		throw new NoSuchCommandException(commandName);
	}

private static Profiles parseTokens(String expression, StringTokenizer tokens, Context context) {
	List<Profiles> elements = new ArrayList<>();
	Operator operator = null;
	while (tokens.hasMoreTokens()) {
		String token = tokens.nextToken().trim();
		if (token.isEmpty()) {
			continue;
		}
		switch (token) {
			case "(" -> {
				Profiles contents = parseTokens(expression, tokens, Context.PARENTHESIS);
				if (context == Context.NEGATE) {
					return contents;
				}
				elements.add(contents);
			}
			case "&" -> {
				assertWellFormed(expression, operator == null || operator == Operator.AND);
				operator = Operator.AND;
			}
			case "|" -> {
				assertWellFormed(expression, operator == null || operator == Operator.OR);
				operator = Operator.OR;
			}
			case "!" -> elements.add(not(parseTokens(expression, tokens, Context.NEGATE)));
			case ")" -> {
				if (context == Context.PARENTHESIS) {
					return merge(expression, elements, operator);
				}
				assertWellFormed(expression, false);
			}
			default -> {
				Profiles value = equals(token);
				if (context == Context.NEGATE) {
					return value;
				}
				elements.add(value);
			}
		}
	}
	assertWellFormed(expression, context != Context.PARENTHESIS);
	return merge(expression, elements, operator);
}

private static ResolvableType resolveVariable(TypeVariable<?> typeVariable, ResolvableType contextType) {
	ResolvableType resolvedType;
	if (contextType.hasGenerics()) {
		ResolvableType.VariableResolver variableResolver = contextType.asVariableResolver();
		if (variableResolver == null) {
			return ResolvableType.NONE;
		}
		resolvedType = variableResolver.resolveVariable(typeVariable);
		if (resolvedType != null) {
			while (resolvedType.getType() instanceof TypeVariable<?>) {
				resolvedType = resolvedType.resolveType();
			}
			return resolvedType;
		}
	}

	ResolvableType superType = contextType.getSuperType();
	if (superType != ResolvableType.NONE) {
		resolvedType = resolveVariable(typeVariable, superType);
		if (resolvedType != ResolvableType.NONE) {
			return resolvedType;
		}
	}
	for (ResolvableType ifc : contextType.getInterfaces()) {
		resolvedType = resolveVariable(typeVariable, ifc);
		if (resolvedType != ResolvableType.NONE) {
			return resolvedType;
		}
	}
	return ResolvableType.NONE;
}

public static <T> Map<Method, T> selectMethods(Class<?> targetType, final MetadataLookup<T> metadataLookup) {
	final Map<Method, T> methodMap = new LinkedHashMap<>();
	Set<Class<?>> handlerTypes = new LinkedHashSet<>();
	Class<?> specificHandlerType = null;

	if (!Proxy.isProxyClass(targetType)) {
		specificHandlerType = ClassUtils.getUserClass(targetType);
		handlerTypes.add(specificHandlerType);
	}
	handlerTypes.addAll(ClassUtils.getAllInterfacesForClassAsSet(targetType));

	for (Class<?> currentHandlerType : handlerTypes) {
		final Class<?> targetClass = (specificHandlerType != null ? specificHandlerType : currentHandlerType);

		ReflectionUtils.doWithMethods(currentHandlerType, method -> {
			Method specificMethod = ClassUtils.getMostSpecificMethod(method, targetClass);
			T result = metadataLookup.inspect(specificMethod);
			if (result != null) {
				Method bridgedMethod = BridgeMethodResolver.findBridgedMethod(specificMethod);
				if (bridgedMethod == specificMethod || bridgedMethod == method ||
						bridgedMethod.equals(specificMethod) || bridgedMethod.equals(method) ||
						metadataLookup.inspect(bridgedMethod) == null) {
					methodMap.put(specificMethod, result);
				}
			}
		}, ReflectionUtils.USER_DECLARED_METHODS);
	}

	return methodMap;
}

public ResolvableType[] getGenerics() {
	if (this == NONE) {
		return EMPTY_TYPES_ARRAY;
	}
	ResolvableType[] generics = this.generics;
	if (generics == null) {
		if (this.type instanceof Class<?> clazz) {
			Type[] typeParams = clazz.getTypeParameters();
			if (typeParams.length > 0) {
				generics = new ResolvableType[typeParams.length];
				for (int i = 0; i < generics.length; i++) {
					generics[i] = ResolvableType.forType(typeParams[i], this);
				}
			}
			else {
				generics = EMPTY_TYPES_ARRAY;
			}
		}
		else if (this.type instanceof ParameterizedType parameterizedType) {
			Type[] actualTypeArguments = parameterizedType.getActualTypeArguments();
			if (actualTypeArguments.length > 0) {
				generics = new ResolvableType[actualTypeArguments.length];
				for (int i = 0; i < actualTypeArguments.length; i++) {
					generics[i] = forType(actualTypeArguments[i], this.variableResolver);
				}
			}
			else {
				generics = EMPTY_TYPES_ARRAY;
			}
		}
		else {
			generics = resolveType().getGenerics();
		}
		this.generics = generics;
	}
	return generics;
}

private TableMetaData findTableMetaData(@Nullable String schemaName, @Nullable String tableName,
			Map<String, TableMetaData> tableMeta) {

		if (schemaName != null) {
			TableMetaData tmd = tableMeta.get(schemaName.toUpperCase(Locale.ROOT));
			if (tmd == null) {
				throw new DataAccessResourceFailureException("Unable to locate table meta-data for '" +
						tableName + "' in the '" + schemaName + "' schema");
			}
			return tmd;
		}
		else if (tableMeta.size() == 1) {
			return tableMeta.values().iterator().next();
		}
		else {
			TableMetaData tmd = tableMeta.get(getDefaultSchema());
			if (tmd == null) {
				tmd = tableMeta.get(this.userName != null ? this.userName.toUpperCase(Locale.ROOT) : "");
			}
			if (tmd == null) {
				tmd = tableMeta.get("PUBLIC");
			}
			if (tmd == null) {
				tmd = tableMeta.get("DBO");
			}
			if (tmd == null) {
				throw new DataAccessResourceFailureException(
						"Unable to locate table meta-data for '" + tableName + "' in the default schema");
			}
			return tmd;
		}
	}

@Override
	public String toString() {
		String[] parameterNames = getParameterNames();
		if (parameterNames != null) {
			StringJoiner result = new StringJoiner(", ", getClass().getSimpleName() + " {", "}");
			for (String parameterName : parameterNames) {
				Object value = getValue(parameterName);
				if (value instanceof SqlParameterValue sqlParameterValue) {
					value = sqlParameterValue.getValue();
				}
				String typeName = getTypeName(parameterName);
				if (typeName == null) {
					int sqlType = getSqlType(parameterName);
					if (sqlType != TYPE_UNKNOWN) {
						typeName = JdbcUtils.resolveTypeName(sqlType);
						if (typeName == null) {
							typeName = String.valueOf(sqlType);
						}
					}
				}
				StringBuilder entry = new StringBuilder();
				entry.append(parameterName).append('=').append(value);
				if (typeName != null) {
					entry.append(" (type:").append(typeName).append(')');
				}
				result.add(entry);
			}
			return result.toString();
		}
		else {
			return getClass().getSimpleName();
		}
	}

@SuppressWarnings("JavaExistingMethodCanBeUsed")
	private static URI initUri(HttpServletRequest servletRequest) {
		Assert.notNull(servletRequest, "'request' must not be null");
		String urlString = null;
		String query = null;
		boolean hasQuery = false;
		try {
			StringBuffer requestURL = servletRequest.getRequestURL();
			query = servletRequest.getQueryString();
			hasQuery = StringUtils.hasText(query);
			if (hasQuery) {
				requestURL.append('?').append(query);
			}
			urlString = requestURL.toString();
			return new URI(urlString);
		}
		catch (URISyntaxException ex) {
			if (hasQuery) {
				String requestURL = servletRequest.getRequestURL().toString();
				try {
					// Maybe malformed query, try to encode it
					return new URI(requestURL + "?" + encodeQuery(query));
				}
				catch (URISyntaxException ex2) {
					try {
						// Try leaving it out
						return new URI(requestURL);
					}
					catch (URISyntaxException ex3) {
						// ignore
					}
				}
			}
			throw new IllegalStateException(
					"Could not resolve HttpServletRequest as URI: " + urlString, ex);
		}
	}

