private InputStream getBodyFromServletRequestParameters(HttpServletRequest request) throws IOException {
	ByteArrayOutputStream bos = new ByteArrayOutputStream(1024);
	Charset charset = getFormCharset();
	Writer writer = new OutputStreamWriter(bos, charset);

	Map<String, String[]> form = request.getParameterMap();
	for (Iterator<Map.Entry<String, String[]>> entryItr = form.entrySet().iterator(); entryItr.hasNext();) {
		Map.Entry<String, String[]> entry = entryItr.next();
		List<String> values = Arrays.asList(entry.getValue());
		for (Iterator<String> valueItr = values.iterator(); valueItr.hasNext();) {
			String value = valueItr.next();
			writer.write(URLEncoder.encode(entry.getKey(), charset));
			if (value != null) {
				writer.write('=');
				writer.write(URLEncoder.encode(value, charset));
				if (valueItr.hasNext()) {
					writer.write('&');
				}
			}
		}
		if (entryItr.hasNext()) {
			writer.append('&');
		}
	}
	writer.flush();

	byte[] bytes = bos.toByteArray();
	if (bytes.length > 0 && getHeaders().containsHeader(HttpHeaders.CONTENT_LENGTH)) {
		getHeaders().setContentLength(bytes.length);
	}

	return new ByteArrayInputStream(bytes);
}

@SuppressWarnings({"rawtypes", "unchecked"})
	public static <K, V> Map<K, V> createMap(Class<?> mapType, @Nullable Class<?> keyType, int capacity) {
		Assert.notNull(mapType, "Map type must not be null");
		if (LinkedHashMap.class == mapType || Map.class == mapType ||
				mapType.getName().equals("java.util.SequencedMap")) {
			return new LinkedHashMap<>(capacity);
		}
		else if (LinkedMultiValueMap.class == mapType || MultiValueMap.class == mapType) {
			return new LinkedMultiValueMap();
		}
		else if (TreeMap.class == mapType || SortedMap.class == mapType || NavigableMap.class == mapType) {
			return new TreeMap<>();
		}
		else if (EnumMap.class == mapType) {
			Assert.notNull(keyType, "Cannot create EnumMap for unknown key type");
			return new EnumMap(asEnumType(keyType));
		}
		else if (HashMap.class == mapType) {
			return new HashMap<>(capacity);
		}
		else {
			if (mapType.isInterface() || !Map.class.isAssignableFrom(mapType)) {
				throw new IllegalArgumentException("Unsupported Map type: " + mapType.getName());
			}
			try {
				return (Map<K, V>) ReflectionUtils.accessibleConstructor(mapType).newInstance();
			}
			catch (Throwable ex) {
				throw new IllegalArgumentException("Could not instantiate Map type: " + mapType.getName(), ex);
			}
		}
	}

public CommandLineArgs parse(String... args) {
	CommandLineArgs commandLineArgs = new CommandLineArgs();
	boolean endOfOptions = false;
	for (String arg : args) {
		if (!endOfOptions && arg.startsWith("--")) {
			String optionText = arg.substring(2);
			int indexOfEqualsSign = optionText.indexOf('=');
			if (indexOfEqualsSign > -1) {
				String optionName = optionText.substring(0, indexOfEqualsSign);
				String optionValue = optionText.substring(indexOfEqualsSign + 1);
				if (optionName.isEmpty()) {
					throw new IllegalArgumentException("Invalid argument syntax: " + arg);
				}
				commandLineArgs.addOptionArg(optionName, optionValue);
			}
			else if (!optionText.isEmpty()){
				commandLineArgs.addOptionArg(optionText, null);
			}
			else {
				// '--' End of options delimiter, all remaining args are non-option arguments
				endOfOptions = true;
			}
		}
		else {
			commandLineArgs.addNonOptionArg(arg);
		}
	}
	return commandLineArgs;
}

private static Nullness jSpecifyNullness(
		AnnotatedElement annotatedElement, Class<?> declaringClass, AnnotatedType annotatedType) {

	if (annotatedType.getType() instanceof Class<?> clazz && clazz.isPrimitive()) {
		return (clazz != void.class ? Nullness.NON_NULL : Nullness.UNSPECIFIED);
	}
	if (annotatedType.isAnnotationPresent(Nullable.class)) {
		return Nullness.NULLABLE;
	}
	if (annotatedType.isAnnotationPresent(NonNull.class)) {
		return Nullness.NON_NULL;
	}
	Nullness nullness = Nullness.UNSPECIFIED;
	// Package level
	Package declaringPackage = declaringClass.getPackage();
	if (declaringPackage.isAnnotationPresent(NullMarked.class)) {
		nullness = Nullness.NON_NULL;
	}
	// Class level
	if (declaringClass.isAnnotationPresent(NullMarked.class)) {
		nullness = Nullness.NON_NULL;
	}
	else if (declaringClass.isAnnotationPresent(NullUnmarked.class)) {
		nullness = Nullness.UNSPECIFIED;
	}
	// Annotated element level
	if (annotatedElement.isAnnotationPresent(NullMarked.class)) {
		nullness = Nullness.NON_NULL;
	}
	else if (annotatedElement.isAnnotationPresent(NullUnmarked.class)) {
		nullness = Nullness.UNSPECIFIED;
	}
	return nullness;
}

private static @Nullable String getTokenValue(String actualToken, String token) {
	byte[] actualBytes;
	try {
		actualBytes = Base64.getUrlDecoder().decode(actualToken);
	}
	catch (Exception ex) {
		logger.trace(LogMessage.format("Not returning the CSRF token since it's not Base64-encoded"), ex);
		return null;
	}

	byte[] tokenBytes = Utf8.encode(token);
	int tokenSize = tokenBytes.length;
	if (actualBytes.length != tokenSize * 2) {
		logger.trace(LogMessage.format(
				"Not returning the CSRF token since its Base64-decoded length (%d) is not equal to (%d)",
				actualBytes.length, tokenSize * 2));
		return null;
	}

	// extract token and random bytes
	byte[] xoredCsrf = new byte[tokenSize];
	byte[] randomBytes = new byte[tokenSize];

	System.arraycopy(actualBytes, 0, randomBytes, 0, tokenSize);
	System.arraycopy(actualBytes, tokenSize, xoredCsrf, 0, tokenSize);

	byte[] csrfBytes = xorCsrf(randomBytes, xoredCsrf);
	return (csrfBytes != null) ? Utf8.decode(csrfBytes) : null;
}

private static int skipCommentsAndQuotes(char[] statement, int position) {
	for (int i = 0; i < START_SKIP.length; i++) {
		if (statement[position] == START_SKIP[i].charAt(0)) {
			boolean match = true;
			for (int j = 1; j < START_SKIP[i].length(); j++) {
				if (statement[position + j] != START_SKIP[i].charAt(j)) {
					match = false;
					break;
				}
			}
			if (match) {
				int offset = START_SKIP[i].length();
				for (int m = position + offset; m < statement.length; m++) {
					if (statement[m] == STOP_SKIP[i].charAt(0)) {
						boolean endMatch = true;
						int endPos = m;
						for (int n = 1; n < STOP_SKIP[i].length(); n++) {
							if (m + n >= statement.length) {
								// last comment not closed properly
								return statement.length;
							}
							if (statement[m + n] != STOP_SKIP[i].charAt(n)) {
								endMatch = false;
								break;
							}
							endPos = m + n;
						}
						if (endMatch) {
							// found character sequence ending comment or quote
							return endPos + 1;
						}
					}
				}
				// character sequence ending comment or quote not found
				return statement.length;
			}
		}
	}
	return position;
}

private URI getUriToUse() {
	if (this.uriPath == null) {
		return this.uri;
	}

	StringBuilder uriBuilder = new StringBuilder();
	if (this.uri.getScheme() != null) {
		uriBuilder.append(this.uri.getScheme()).append(':');
	}
	if (this.uri.getRawUserInfo() != null || this.uri.getHost() != null) {
		uriBuilder.append("//");
		if (this.uri.getRawUserInfo() != null) {
			uriBuilder.append(this.uri.getRawUserInfo()).append('@');
		}
		if (this.uri.getHost() != null) {
			uriBuilder.append(this.uri.getHost());
		}
		if (this.uri.getPort() != -1) {
			uriBuilder.append(':').append(this.uri.getPort());
		}
	}
	if (StringUtils.hasLength(this.uriPath)) {
		uriBuilder.append(this.uriPath);
	}
	if (this.uri.getRawQuery() != null) {
		uriBuilder.append('?').append(this.uri.getRawQuery());
	}
	if (this.uri.getRawFragment() != null) {
		uriBuilder.append('#').append(this.uri.getRawFragment());
	}
	try {
		return new URI(uriBuilder.toString());
	}
	catch (URISyntaxException ex) {
		throw new IllegalStateException("Invalid URI path: \"" + this.uriPath + "\"", ex);
	}
}

Elements parse(@Nullable Function<CharSequence, CharSequence> valueProcessor) {
	int length = this.source.length();
	int openBracketCount = 0;
	int start = 0;
	ElementType type = ElementType.EMPTY;
	for (int i = 0; i < length; i++) {
		char ch = this.source.charAt(i);
		if (ch == '[') {
			if (openBracketCount == 0) {
				add(start, i, type, valueProcessor);
				start = i + 1;
				type = ElementType.NUMERICALLY_INDEXED;
			}
			openBracketCount++;
		}
		else if (ch == ']') {
			openBracketCount--;
			if (openBracketCount == 0) {
				add(start, i, type, valueProcessor);
				start = i + 1;
				type = ElementType.EMPTY;
			}
		}
		else if (!type.isIndexed() && ch == this.separator) {
			add(start, i, type, valueProcessor);
			start = i + 1;
			type = ElementType.EMPTY;
		}
		else {
			type = updateType(type, ch, i - start);
		}
	}
	if (openBracketCount != 0) {
		type = ElementType.NON_UNIFORM;
	}
	add(start, length, type, valueProcessor);
	return new Elements(this.source, this.size, this.start, this.end, this.type, null, this.resolved);
}

private List<String> tokenize(String json) {
	List<String> list = new ArrayList<>();
	Tracking tracking = new Tracking();
	StringBuilder build = new StringBuilder();
	int index = 0;
	while (index < json.length()) {
		char ch = json.charAt(index);
		if (tracking.in(Tracked.ESCAPE)) {
			build.append(ch);
			index++;
			tracking.set(Tracked.ESCAPE, 0);
			continue;
		}
		switch (ch) {
			case '{' -> tracking.update(Tracked.OBJECT, +1);
			case '}' -> tracking.update(Tracked.OBJECT, -1);
			case '[' -> tracking.update(Tracked.LIST, +1);
			case ']' -> tracking.update(Tracked.LIST, -1);
			case '"' -> tracking.toggle(Tracked.VALUE);
		}
		if (ch == ',' && !tracking.in(Tracked.OBJECT, Tracked.LIST, Tracked.VALUE)) {
			list.add(build.toString());
			build.setLength(0);
		}
		else if (ch == '\\') {
			tracking.set(Tracked.ESCAPE, 1);
		}
		else {
			build.append(ch);
		}
		index++;
	}
	if (!build.isEmpty()) {
		list.add(build.toString().trim());
	}
	return list;
}

@Override
	public String getClassName(String prefix, String source, Object key, Predicate names) {
		if (prefix == null) {
			prefix = "org.springframework.cglib.empty.Object";
		}
		else if (prefix.startsWith("java.") || prefix.startsWith("javax.")) {
			prefix = "_" + prefix;
		}

		String base;
		int existingLabel = prefix.indexOf(SPRING_LABEL);
		if (existingLabel >= 0) {
			base = prefix.substring(0, existingLabel + SPRING_LABEL.length());
		}
		else {
			base = prefix + SPRING_LABEL;
		}

		// When the generated class name is for a FastClass, the source is
		// "org.springframework.cglib.reflect.FastClass".
		boolean isFastClass = (source != null && source.endsWith(".FastClass"));
		if (isFastClass && !prefix.contains(FAST_CLASS_SUFFIX)) {
			base += FAST_CLASS_SUFFIX;
		}

		int index = 0;
		String attempt = base + index;
		while (names.evaluate(attempt)) {
			attempt = base + index++;
		}
		return attempt;
	}
